+fn validate_superblock_tree_level(field: &'static str, level: u8) -> Result<(), ParseError> {
+    if level > BTRFS_MAX_LEVEL {
+        return Err(ParseError::InvalidField {
+            field,
+            reason: "exceeds btrfs max tree level",
+        });
+    }
+    Ok(())
+}
